import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"浑天宝鉴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/功法/浑天宝鉴.md","filePath":"4.资源分区/2.改造与功法/功法/浑天宝鉴.md"}'),s={name:"4.资源分区/2.改造与功法/功法/浑天宝鉴.md"};function d(o,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"浑天宝鉴",tabindex:"-1"},[t("浑天宝鉴 "),r("a",{class:"header-anchor",href:"#浑天宝鉴","aria-label":'Permalink to "浑天宝鉴"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="浑天宝鉴-1" tabindex="-1">浑天宝鉴 <a class="header-anchor" href="#浑天宝鉴-1" aria-label="Permalink to &quot;浑天宝鉴&quot;">​</a></h1><p>功法：浑天宝鉴<br> 描述：出自港漫《天子传奇》中的天子武学，相传由女娲大神所创。<br> 上古之时，共工怒触不周山，女娲大神炼石补天，后来遗留下来十枚天晶，蕴藏天地自然中的种种能量，从这十枚天晶中，便诞生了浑天宝鉴的十重功法。<br> 商周之时，周武王习练此功，击败商纣，创下周朝基业。而后秦始皇嬴政以此功夺得王位。之后天晶四处流落，但是有机会得到天晶的人物无不是一时英豪，足见此功威力无穷，玄妙非常。<br> 下列的浑天宝鉴每一个境界都必须按照次序购买。虽然原著也出现了嬴政逆运浑天宝鉴，但是嬴政本身也是在已经掌握九层浑天宝鉴的情况下，将自己已经掌握的层数逆运，并且这个过程也是凶险无比。因而主神仅向轮回者开放按照次序兑换。</p><p>白云烟<br> 价格：D+850<br> 描述：《浑天宝鉴》的第一境界。真气犹如蒸烟升腾而出，弥漫如瘴，蔽人眼目，扰乱敌人。<br> 【浑天真气】：修炼《浑天宝鉴》所产生的真气。你开启名为“浑天真气”的能量池。“浑天真气”是一个强化能量池，关键属性为耐力，并且能量池大小为耐力*2。由于“浑天真气”是强化能量池，所以其大小会根据人物最高内在强化等级具有额外加成，为D5、C10、B15、A20、S25。<br> 浑天真气是内力变体，因而也可以用于推动一切需要内力推动的资源。<br> 【云烟弥漫】：以一个移动动作，支付2点浑天真气，你可以调动浑天真气，以白云烟境界让真气化作云雾烟气，缭绕身周。这是一次特殊的格挡，通过这次格挡，你所得到的不是格挡防御，而是遮蔽防御，并且你这次格挡得到的遮蔽防御的数值还会提升你的浑天真气能量池等级*2+1点。</p><p>玫霞荡<br> 价格：D+1000<br> 描述：《浑天宝鉴》的第二境界。真气染成赤霞光彩，旋转卷绕，荡劲卸力，能够四两拨千斤，挪移敌人攻击。<br> 【玫霞激荡】：以一个标准动作，支付2点浑天真气，你可以将浑天真气以玫霞荡境界运用，在身周形成霞气激荡，将敌人的攻击卸区。这是一次特殊的全力防御。<br> 这次全力防御将不具有原本的效果，而改为在这次全力防御期间，你的基础防御翻倍计算，基础防御的类型变为偏斜防御，并且你还将额外获得获得你通过白云烟格挡获得的遮蔽防御数量的偏斜防御。<br> 当你的耐力属性低于6时，你施展【玫霞激荡】时只能以半速进行移动。这个效果将会持续到施展【玫霞激荡】者的下个回合开始。<br> 在你因【玫霞激荡】而获得的偏斜防御存在的期间，你在反射豁免上会获得你的浑天真气能量池等级*4点能量加值，并且你在防御上具有基于你的偏斜防御的【防弹】与【防能量】。<br> 这一层级并非浑天宝鉴产生质变的层级，因而视为一个技艺类兑换而非功法类兑换。</p><p>土昆仑<br> 价格：C+1200<br> 描述：《浑天宝鉴》的第三境界。真气参悟坤土之道，有劈山裂石之威势，能够将泥沙土石驱如臂使，激射而出。<br> 【真气雄浑】：地势坤，以厚德载物。宝鉴修行到这一境界之后，真气雄浑远远胜于前两个境界，在驱使浑天真气时，所需要的运功时间大大减少。<br> 从现在起，你每轮额外获得2点AP，仅能用于转化施展《浑天宝鉴》能力所需要的动作。<br> 【土石飞射】：以一个标准动作，支付6点浑天真气，你可以将浑天真气以土昆仑境界运用，操纵固体物体飞升而出伤人。<br> 你进行一次正常的以天生武器进行的攻击或以C等级以上的白刃武器（只有这等品质的武器才能传导土昆仑真气）进行的白刃攻击。这次攻击变为以你的前方15米扇形范围内的所有敌人为对象的群体攻击，并且无论原本你的攻击伤害类型为何种伤害类型，这次攻击都会造成钝击伤害。<br> 这次攻击会额外承受你的浑天真气能量池等级*2点的技艺减值，并且获得你的你的浑天真气能量池等级*2点的附加成功。<br> 这一效果必须要在你的敏感范围内存在固体的情况下才能够使用，在宇宙，空中等环境如果没有固体物质可以调动的话则无法使用。<br> 【境界推演】：伴随着浑天宝鉴修行到更加精深的境界，你对于天地之间的自然能量有了更为深厚的理解。以更高的境界运转先前已经掌握的法门便能够事半功倍。<br> 支付4XP，你可以将从土昆仑境界中得到的领悟融入先前的境界中。现在你施展土昆仑之前的两重境界的主动效果，计算其收益时，你的浑天真气的能量池等级视为比原本的高一级。这一能量池等级提升不会影响其他资源。</p><p>碧雪冰<br> 价格：C+2000<br> 描述：《浑天宝鉴》的第四境界。真气化作森然寒气，无孔不入，能够浸透肌骨，令经脉气血也一并冰洁。<br> 【起霜凝冰】：以一个移动动作，支付6点浑天真气，你可以将浑天真气以碧雪冰境界运用，令自己的出招附带能够冰结经脉气血的冻气，持续一个场景。<br> 在【起霜凝冰】生效期间，你可以将自己的攻击造成的伤害改为冻寒伤害，并且你所进行的攻击附带二分之一的冻结点数，你还可以选择将你的攻击伤害的二分之一转化为冻结点数。<br> 只要你在【起霜凝冰】生效期间对敌人造成了伤害，那么你就可以在对手体内留下碧雪冰真气。残留在敌人体内的碧雪冰真气会令敌人在一轮时间内的强韧豁免与反射豁免上承受你的浑天真气能量池等级*2点的能量减值。<br> 这一层级并非浑天宝鉴产生质变的层级，因而视为一个技艺类兑换，而非功法类兑换。</p><p>紫星河<br> 价格：B+2400<br> 描述：《浑天宝鉴》的第五境界。真气如同川流奔涌而出，运功之时，真气之间浮现无数璀璨星光，宛如星河随心而动，劲力以刚柔并济为特点。<br> 【真气浩大】：星垂平野阔，劲似大江流。修炼浑天真气到此等境界之后，你的真气犹如河江汹涌奔流，运使宝鉴法门更加轻易。<br> 从现在起，你每轮额外获得4点AP，仅能用于转化施展《浑天宝鉴》能力所需要的动作。这一效果将覆盖C级别的【真气雄浑】的效果。<br> 同时针对紫星河这一境界进行钻研，还能够令你的真气变得更为庞大。只要你兑换了浑天宝鉴下属技能树中任意一个名称中含有“星河”的技艺，那么你的浑天真气能量的大小将扩大6点。<br> 同时只要你的浑天真气能量池不为空，你的防御上将额外具有5点偏斜防御和1点基于偏斜防御的附加成功。<br> 【星河奔涌】：以一个迅捷动作，支付10点浑天真气，你可以将浑天真气以紫星河境界运用，令自己的下一次攻击缠绕星河气劲。<br> 星河刚柔并济，首先能够以柔劲破去对手的甲胄或是硬功的防护，直接将劲力打入对手躯体。你的这次攻击附带【接触攻击】特性。<br> 并且由于柔劲能够让劲力在对手的四肢百骸中游走，绵绵不绝。你的这次攻击附带【碾压】特性，这表现为你打入对手体内的柔劲对对手的内脏，筋骨造成影响。<br> 而在星河劲力灌入对手体内后，就会由柔变刚，完全爆发其破坏力。你的这次攻击造成的伤害提升一倍。<br> 【境界推演（提升）】：伴随着浑天宝鉴修行到更加精深的境界，你对于天地之间的自然能量有了更为深厚的理解。以更高的境界运转先前已经掌握的法门便能够事半功倍。<br> 支付11XP，你可以将从紫星河境界中得到的领悟融入先前的境界中。现在你施展紫星河之前的四重境界的主动效果（仅包含本体，不包含对应下属技能），计算其收益时，你的浑天真气的能量池等级视为比原本的高一级。这一能量池等级提升不会影响其他资源。<br> 这一效果如果重复作用于相同的浑天宝鉴境界，则效果叠加，例如一个将浑天宝鉴修行到紫星河境界的轮回者，在计算其从白云烟的主动效果中得到的增益时，浑天真气的能量池等级提升两级，此时他的能量池等级为B级，本来应该得到3*2+1=7点额外的遮蔽防御，但是由于经过两级的提升，此时他将得到11点遮蔽防御。<br> 后续相同描述的效果不再赘述。</p><p>暗混沌<br> 价格：B+3000<br> 描述：《浑天宝鉴》的第六境界。真气浑厚凝重，能够犹如无穷无尽的浑浊黑暗一般，令袭来的攻击陷入其中，如泥牛入海，消散无踪。<br> 此一层原名玄混沌，但轮回空间大能【逆位战车】在整理之时，感到此名与浑天宝鉴的最高境界玄宇宙重合，不利于分辨和轮回者对于功法的理解，因而将玄混沌改名暗混沌。<br> 【混沌吞没】：在施展白云烟中的【云烟弥漫】时，你可以将投入的浑天真气的数量提升到10点，此时你便可以将浑天真气以暗混沌境界运用，随即你身体周围将萦绕着深邃的黑暗，吞没对手的攻击。<br> 在【云烟弥漫】具有的效果的基础上，你在这次格挡生效期间，额外具有基于你的遮蔽防御的浑天真气能量池等级*3点的DR/-，并且你具有基于你的遮蔽防御的【超级坚韧】效果。<br> 这一层级并非浑天宝鉴产生质变的层级，因而视为一个技艺类兑换而非功法类兑换。</p><p>靛沧海<br> 价格：B+4000<br> 描述：《浑天宝鉴》的第七境界。真气如同沧海无边，既有平静安宁的无垠宽广，又有风云骤起的怒海狂涛，可攻可守，毫无破绽。<br> 【沧海变幻】：你从浑天宝鉴下属技能树中的“鲸吞势、滔天势、深渊势、浪卷势、茧困势”五个技艺中选择一个取得。在此之后，你每额外取得一个这五个技艺中你未取得的技艺，则你的浑天真气能量池扩大9点，并且你在【星河奔涌】中获得的偏斜防御加值提升5点。你最多可以反复获得这个增益两次。<br> 这一层级并非浑天宝鉴产生质变的层级，因而视为一个技艺类兑换而非功法类兑换。</p><p>金晨曦<br> 价格：A+4000<br> 描述：《浑天宝鉴》的第八境界。真气如同旭日东升，至正至阳。运功之时真气外放，将使用者笼罩其中，在旁人观来犹如太阳金光大作，驱散群邪。<br> 【金曦普照】：在施展白云烟中的【玫霞激荡】时，你可以将投入的浑天真气的数量提升到14点，此时你便可以将浑天真气以金晨曦境界运用，随即你身体周围金光照耀，不仅能够将攻击以强横真气磨灭，而且还能够以令气劲绽放而出，夺目伤人。<br> 在【玫霞激荡】具有的效果的基础上，你在这次全力防御生效期间，额外具有8点偏斜防御，并且一轮一次，可以将自己受到的近战伤害降低到原本的一半。<br> 当你发动这次将伤害减半的效果时，你可以选择在此时激发金晨曦真气的威力，从而立即进行一次不附带任何招式的近战攻击，这次近战攻击无论原本造成何种伤害，现在都将造成光能伤害。被这次攻击命中的敌人需要以自身的强韧豁免对抗你这一次攻击的出目，如果对抗失败，则将会陷入A级别创伤来源的目盲状态。这个目盲状态持续一轮。<br> 这在画风上表现为对手的攻击在和你护体的金晨曦真气碰撞之时，你的护体真气金光大作，不仅以威力将对手灼伤，而且还以强光令对手的双目失明。<br> 这一层级并非浑天宝鉴产生质变的层级，因而视为一个技艺类兑换而非功法类兑换。</p><p>血穹苍<br> 价格：A+4800<br> 描述：《浑天宝鉴》的第九境界。真气之神妙更为深入，直指生命本源。运功之时，能够汲取他人精血为己所用，杀性血气直冲云霄，苍天为之变色，故名“血穹苍”。<br> 【真气磅礴】：修炼到此等境界之后，你便能够从浑天宝鉴之中参悟出自天地演化出生命的深奥道理。你的真气之磅礴达到了一种惊人的境界，宛如与天地之造化元气相通，取之不尽用之不竭。<br> 从现在起，你每轮额外获得8点AP，仅能用于转化施展《浑天宝鉴》能力所需要的动作。这一效果将覆盖B级别的【真气浩大】的效果。<br> 同时针对紫星河这一境界进行钻研，还能够令你的真气变得更为庞大。只要你兑换了浑天宝鉴下属技能树中任意一个名称中含有“穹苍”的技艺，那么你的浑天真气能量的大小将扩大12点。你最多能够获得这个效果三次。并且你每次通过这个效果扩大自身的真气能量池时，你可以下述三个效果中选择一个取得。<br> 壹·穹苍无边：以血苍穹真气在自己身边升腾起圆一丈的血红护体气劲，原著飘渺城主中用出时，能将整个大殿映照得通红如血。<br> 只需要每回合以自由动作维持，并且保证消耗4点浑天真气，穹苍无边的护体气劲就会在你的身边显现。只要穹苍无边生效，你就具有基于偏斜防御的【劣化3】。<br> 贰·穹苍无涯：全力运功，以血苍穹祭出一道上达天空的血柱，原著田玄子使出时，恐怖的威力令整个峡谷之上的云层尽数变色。<br> 以一个自由动作，消耗10点真气，你下一次以浑天真气推动的攻击将以你的敏感范围内的所有敌人为目标，并且加骰上升一级，至多为8加骰。<br> 叁·穹苍无悔：被誉为血苍穹境界的极限绝招，是不顾一切，祭出自己的最大限度功力的一击，出招之时，周身功力化作血色云气冲起，威势令人胆寒。<br> 这一能力必须在兑换了其他两种可选能力之后才能获得。<br> 一天一次，你可以花费一个标准动作，对自身造成24L伤害，你可以施展穹苍无悔，你的下一次以浑天真气推动的招式将会造成韧性伤害，并且造成的伤害翻倍。<br> 【血色苍穹】：以一个整轮动作，你可以将浑天真气以血穹苍境界运用。运功之时，被你功力影响的范围之内，苍天变色，天地的精气朝你聚集，一切范围内的生灵的血气与生机都由你掌握。<br> 血穹苍真气会充盈在你的整个敏感范围之内，这可能会带来苍穹变色等画风效果。每回合一次，你可以额外对你的敏感范围内的所有敌人进行一次攻击，无论你的攻击原本造成什么伤害，在这次攻击中都将改为造成亵渎伤害。并且每轮的这次攻击都将附带等额的流血点数，这表现为处于你血穹苍真气影响范围内的所有敌人都将被你的运功影响气血的流转，令其生命逐渐衰弱。<br> 只要你开启了血色穹苍起码一轮，那么由于你能够以血苍穹吸纳天地元气，你获得2点快速治疗（医疗点24）。之后每保持开启一轮，你都还能额外获得3点快速医疗（医疗点36），你最多能获得这个效果两次。<br> 从开启血色苍穹的第二轮起，只要你以血色苍穹所附赠的攻击确实地造成了流血点数，那么你在血色苍穹持续时间内就具有3点【吸血】。这表现为你牵引被你的真气所影响的人的气血进入你的体内。当你因为血色苍穹的效果获得了8点快速医疗时，你所具有【吸血】的数额将提升到9点。</p><p>玄宇宙<br> 价格：S+9600<br> 描述：《浑天宝鉴》的第十境界。以自身的力量掌控宇宙变化的奥妙，将天地创生与毁灭的奥妙融入武学之中，拥有二化与三变。<br> 二化分别是以自身力量模仿牵引吞噬一切的黑洞力量，将一切攻杀而来的招式吸收的“化解”，与模仿白洞力量，将黑洞力量所吸纳的攻击返还的“归真”。<br> 三变分别是：以宇宙创生，混沌开辟，一切自无到有为奥妙的第一变“大爆炸”，以天体运行有序，空间运转有时为奥妙的第二变“天行健”，以及以宇宙膨胀，万籁归寂，一切虚空为奥妙的第三变“归虚空”。</p><p>玄宇宙·四维力量<br> 价格：SSS+38400<br> 描述：在完全掌握玄宇宙之后才能掌握的至高境界，凌驾于空间之上，将第四维度时空的力量也加以掌握，用于迎战自第五维度而来的敌人。<br> 暂不开放。</p><p>下属技能树：</p><p>冰劈<br> 前提：浑天宝鉴第四境界 碧雪冰<br> 价格：C+1000<br> 描述：将碧雪冰的真气注入刀剑之中，凝结形成锋利而坚固的寒冰，增加杀伤力的招式。<br> 在【起霜凝冰】生效的那一个场景内，消耗一个标准动作和6点浑天真气，你可以施展冰劈。你必须持有一把能够造成挥砍伤害的武器才可以使用冰劈。<br> 你如常以满足条件的武器进行一次攻击，这次攻击中，那把武器的伤害提升你的浑天真气能量池等级*3点，并且这次攻击能够获得【幻灭】特性。<br> 【招式推演】：消耗B+2000，你可以将本招式逐级升级为“崩雪斩·裂冰劈”，能够挥出多道寒冰凝结而成的斩击。此时你施展该招式需要花费10点浑天真气。<br> 你如常以满足条件的武器进行两次攻击，这两次攻击中，那把武器的伤害提升你的浑天真气能量池等级*6点，具有【幻灭】特性，并且能够进行【连射】。<br> 这一效果将取代C级的效果。</p><p>星河气旋<br> 前提：浑天宝鉴第五境界 紫星河<br> 价格：B+2000<br> 描述：以紫星河境界运转真气，将真气形成气流，横扫而出，击退敌人的招式。<br> 消耗一个标准动作和8点浑天真气，你可以施展星河气旋。你如常进行一次攻击，这次攻击改为对半径30米范围内的敌人进行攻击，需要以反射豁免应对。<br> 由于爆发出的气旋具有强大的威力，你这次攻击的出目变为1.5倍，同时席卷而过的气流还能够将敌人吹卷而倒，你可以以一个自由动作将一冲撞结合在这次攻击中。</p><p>逆转星河<br> 前提：浑天宝鉴第五境界 紫星河<br> 价格：B+2500<br> 描述：运转真气，以强横的星河气劲偏转攻击的走向。<br> 消耗10点浑天真气，你可以进行一次特殊的全力防御。这一效果和【玫霞激荡】为相互替换的关系。<br> 与【玫霞激荡】相同，这次全力防御将不具有原本的效果，而改为在这次全力防御期间，你的基础防御的类型变为偏斜防御，并且你还将额外获得获得等同于你的基础防御与你通过白云烟格挡获得的遮蔽防御数量之和的偏斜防御。但这次全力防御并不会如同【玫霞激荡】一样地令你取得反射豁免上的加值，取而代之的是，你在这次全力防御中，会额外获得你的浑天真气能量池等级*5点的偏斜防御，并且具有给予偏斜防御的【适应】特性。<br> 如果这次攻击没有能够对你造成伤害，那么你可以立即将这次攻击的目标更改为对手的这次攻击的攻击范围内的任意一名其他角色。这是一个B级别时空来源的胁迫效果。如果你受到的这次攻击是一次范围攻击，那么你无法通过这个效果令一名角色受到两次伤害，但可以令一个本来不被攻击的对象（例如进行这次范围攻击的角色的友方单位）受到这次攻击的影响。</p><p>鲸吞势<br> 前提：浑天宝鉴第七境界 靛沧海<br> 价格：B+2000<br> 描述：以靛沧海境界使出的招式，真气宛如海中巨鲸捕猎，将敌人吞没。<br> 你可以将施展土石飞射所消耗的浑天真气提升到10点，施展鲸吞势。此时由于你所激射而出的不再是周围的固体，而是以浑天真气形成的巨浪，因而不再需要遵守“这一效果必须要在你的敏感范围内存在固体的情况下才能够使用，在宇宙，空中等环境如果没有固体物质可以调动的话则无法使用。”的限制。<br> 在【土石飞射】的效果的基础上，你这次攻击额外具有4点附加成功，射程增加40米，并且具有【湮灭】。<br> 你所激发而出的真气可以将如水体一般将敌人的行动困锁，所以这次攻击还会令所有被你这次攻击命中的人进行一次反射豁免，dc为伤害值，失败则受到B级别的【潮湿】效果的影响。</p><p>滔天势<br> 前提：浑天宝鉴第七境界 靛沧海<br> 价格：B+2000<br> 描述：以靛沧海境界使出的招式，真气宛如巨浪滔天而起，刚强无比。<br> 在施展【星河奔涌】时可以发动。在【星河奔涌】的效果基础上，你这次攻击加骰提升一级，并且额外具有8点能量加值。<br> 由于滔天势的真气之强，敌人如果被此招击中，便会犹如被滔天巨浪击打，飞射而出，因而受到这一技艺增幅的那次攻击还将具有B级别环境来源的【击飞】效果，目标需要以反射豁免，dc为伤害值，失败则被击飞一轮。<br> 如果你的这次增幅是给予了以剑进行的攻击，则可以被称作“滔天剑势”。</p><p>深渊势<br> 前提：浑天宝鉴第七境界 靛沧海<br> 价格：B+2000<br> 描述：以靛沧海境界使出的招式，真气犹如水势柔巧，以柔克刚，化解攻势。<br> 以移动动作准备一次招架，在受到攻击时以反射动作使用。你这次招架能够抵消的伤害增加你的浑天宝鉴能量池等级*2点，并且你在进行这次招架时，视为移出攻击范围。你在应对这次攻击和这次攻击带来的异常点数等附加效果时，你的强韧豁免和反射豁免的加骰等级提升一级，至多为8加骰。</p><p>浪卷势<br> 前提：浑天宝鉴第七境界 靛沧海<br> 价格：B+2000<br> 描述：以靛沧海境界使出的招式，真气如环形海潮翻卷，束缚敌人行动。<br> 在施展星河气旋时可以发动。在星河气旋的效果的基础上，你的攻击射程提升10米，并且由于靛沧海的真气犹如水势，更加多变，你可以在进行这次攻击时，自由选择以一个自由动作将一次冲撞结合在这次攻击中或是将一次拖拽结合在这一次攻击中。<br> 因为浪涛有层叠之势，你这次攻击还将能够以水势的流动与拍击，扰乱对手的动作。你这次攻击附带等额的纠缠点数，标准豁免。并且如果这次攻击造成伤害，还能令对手承受你的浑天宝鉴能量池等级*4点的反射豁免上的环境减值，持续一轮。<br> 只要你释放了这一技艺，则本轮内，这一技艺所影响的范围对受到靛沧海纠缠点数影响的单位视为B级别环境来源的困难地形。</p><p>茧困势<br> 前提：浑天宝鉴第六境界 暗混沌<br> 价格：B+2000<br> 描述：以靛沧海境界使出的招式，真气犹如茧包覆裹，将敌人困锁其中，虽然以暗混沌境界也能够施展，但是以靛沧海境界施展方才能够发挥出真正威力。<br> 消耗一个标准动作和10点浑天真气，你可以释放茧困势。你如常进行一次攻击，只要这次攻击命中，被命中的敌人需要进行一次反射豁免，DC为成功数，失败则受到B级别的环境来源的定身效果。即使对手具有针对定身效果的免疫，由于茧困势锁蕴含的真气包裹对手身躯所施加的沉重压力，这一次攻击还将附带等额的剧痛点数和纠缠点数，标准豁免。</p><p>朝阳耀天<br> 前提：浑天宝鉴第八境界 金晨曦<br> 价格：A+4000<br> 描述：将金晨曦真气外放而出，化作无数气剑穿刺敌人，宛如朝阳射出光芒普照世间。<br> 在施展星河气旋时，将消耗的浑天真气提升到14点，可以发动。这一技艺和“浪卷势”等其他基于星河气旋的招式并不兼容。<br> 在星河气旋的效果的基础上，你的攻击射程提升100米，加骰提升一级，至多为8加骰。由于金晨曦的真气宛如日光炽热，能够烧灼一切邪恶污秽，你的这次攻击改为造成光能伤害，能够直接造成韧性伤害，并且附带等额的燃烧点数。</p><p>无定飞星<br> 前提：浑天宝鉴第八境界 金晨曦<br> 价格：A+4000<br> 描述：将金晨曦真气凝聚成流星之状，随后以飘忽不定的轨迹激射而出。乃是金晨曦演化招式之中速度最快，最难以躲避的一击。<br> 消耗一个整轮动作和14点浑天真气，你可以施展无定飞星。按照原著来说，无定飞星可以从左右双手各射出一道，因而施展屋无定飞星时，你可以进行两次攻击，这两次攻击射程提升100米，并且均会造成光能伤害。<br> 由于无定飞星犹如流光飞奔，快绝无比，并且轨迹变化莫测，令敌人难以反应，这次两次攻击都附带S级别的【先制】效果，并且具有A级时空来源的忽略闪避防御效果。<br> 这一时空来源具体在画风上的具体表现是无定飞星的性质与流光类似，而从宇宙一道来讲，流光飞驰之速的确难以匹敌，因而无法闪避。<br> 而只要你的这一忽略闪避防御的效果生效，那么无定飞星便可以在对手还未来得及做出反应之时将对手的头颅和心脏等重要部位直接洞穿，本次攻击还将附带A级别的创伤来源的即死效果，目标以反射豁免，失败则即死生效。</p><p>无敌金环<br> 前提：浑天宝鉴第八境界 金晨曦<br> 价格：A+4000<br> 描述：将金晨曦真气环绕身周，并且高速旋转，在释放出炫目金光的同时，塑型出一个由真气凝聚而成的金环，并且将其投射而出的招式。<br> 无敌金环具有两重招式，需要依次施展。<br> 你首先需要以一个标准动作，消耗4点浑天真气，令金晨曦真气在自己的身体周围高速运转，并且将金晨曦压缩凝实，这一过程将会激发出剧烈金光。<br> 你如常进行一次攻击，这次攻击的射程提升100米，并且能够造成光能伤害，附带等额目眩点数，由于金晨曦真气在压缩之时释放出来的光芒之剧烈，这一目眩点数提升为四档异常点数。<br> 在进行了金晨曦真气的压缩之后，金环在你身体周围形成，在下一轮你可以一个标准动作，消费10点浑天真气，令其收缩，纳于手中，而后掷射而出。<br> 将金环掷射同样是一次如常的攻击，这次攻击的射程提升120米，并且能够造成光能伤害。由于金环是由阳刚炙热的金晨曦真气在经过旋转和压缩之后形成的，具有刚猛无匹的威力，所以这一次攻击能够造成三倍伤害，还能够忽略天生防御和盔甲防御，这两个忽略防御均是A级别的时空来源的效果。</p><p>穹苍血甲<br> 前提：浑天宝鉴第九境界 血穹苍<br> 价格：A+4000<br> 描述：将血穹苍真气在身周凝实，暗沉发黑的血色煞气宛如甲胄一般，守护运功者。<br> 以一个移动动作，消耗14点浑天真气，你可以发动穹苍血甲，血甲将在你的身周存在一个场景。<br> 穹苍血甲视为穿着了一件重甲，这件重甲能够提供36/36点偏斜防御，具有2点盔甲减值，并且还具有2点基于这一偏斜防御的防御上的附加成功。如果你身上还穿着有其他甲胄，发动同样也要遵守多重着甲规则。<br> 同时穹苍血甲还能够通过吸收对手的气血，令自身变得更为坚固。在穿着穹苍血甲期间，你在攻击时额外具有【吸血5】。只要你在一轮中以这个吸血，确实回复了生命值，那么在这一轮结束时，你的穹苍血铠为你提供的偏斜防御还将提升10点，提供的基于偏斜防御的附加成功也提升1点。你最多能重复获得这个效果三次。</p><p>穹苍腥风<br> 前提：浑天宝鉴第九境界 血穹苍<br> 价格：A+4000<br> 描述：运功卷起裹挟血腥味的猩红罡风，所过之处生灵气血翻腾，皮肉如遭千刀凌迟。<br> 以一个标准动作，消耗10点浑天真气，你可以发动穹苍腥风。你如常进行一次攻击，这次攻击会对你敏感范围内的所有敌人进行攻击，需要以反射豁免来进行豁免，并且具有8DP的亵渎能量加值。这次攻击同时具有挥砍伤害和亵渎伤害，在需要判断伤害类型时，取二者中更有利的一方。<br> 由于穹苍腥风具有吹刮血肉之威能，能够对敌人的身躯造成极大破坏，这次攻击将附带等额的流血点数和等额的剧痛点数。</p><p>穹苍血雨<br> 前提：浑天宝鉴第九境界 血穹苍<br> 价格：A+4000<br> 描述：以真气化作血色冰柱，化成万千血矢倾盆降下，箭雨覆盖之处大地龟裂，草木枯朽。<br> 以一个标准动作，消耗12点浑天真气，你可以发动穹苍血雨。你如常进行一次攻击，这次攻击会对你敏感范围内的所有敌人进行攻击，需要以反射豁免来进行豁免，并且攻击骰的出目变为1.5倍。这次攻击同时具有穿刺伤害和毒素伤害，在需要判断伤害类型时，取二者中更有利的一方。<br> 由于穹苍血雨具有蚀骨销金之威能，能够不断侵扰敌人，直至将其化为浓水，这次攻击将附带等额的毒素点数</p><p>血雨腥风洗穹苍<br> 前提：浑天宝鉴第九境界 血穹苍<br> 价格：无，在购买了穹苍血雨以及穹苍腥风后自动习得<br> 描述：将腥风血雨两式合一，引动天地血煞之气，形成覆盖战场的毁灭风暴，宛如苍穹泣血，万物归寂。<br> 要施展这一式，必须在前一轮中已经施展过了穹苍腥风和穹苍血雨。<br> 以一个标准动作，消耗14点浑天真气，你可以发动血雨腥风洗穹苍。你如常进行一次攻击，这次攻击会对你敏感范围内的所有敌人进行攻击，需要以反射豁免来进行豁免。这次攻击能够造成三倍伤害，且同时具有亵渎伤害和毒素伤害，在需要判断伤害类型时，取二者中更有利的一方。<br> 由于血雨腥风洗穹苍引动天地煞气，将先前所施展的腥风血雨的力量发挥到极致，你这次攻击将会同时附带针对流血点数的【激爆】和针对毒素点数的【激爆】。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',31)])])}const A=p(s,[["render",d]]);export{h as __pageData,A as default};
